import sys

class Solution:
    def accountsMerge(self, accounts: list[list[str]]) -> list[list[str]]:
        parent = {}
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[rb] = ra
        email_to_name = {}
        for acc in accounts:
            name = acc[0]
            for email in acc[1:]:
                email_to_name[email] = name
                if email not in parent:
                    parent[email] = email
                union(acc[1], email)
        groups = {}
        for email in parent:
            root = find(email)
            groups.setdefault(root, set()).add(email)
        res = []
        for root, emails in groups.items():
            name = email_to_name[root]
            res.append([name] + sorted(emails))
        return res

if __name__ == '__main__':
    data = sys.stdin.read().splitlines()
    if not data:
        sys.exit(0)
    it = iter(data)
    N = int(next(it))
    accounts = []
    for _ in range(N):
        name = next(it).strip()
        M = int(next(it))
        emails = [next(it).strip() for _ in range(M)]
        accounts.append([name] + emails)
    sol = Solution()
    merged = sol.accountsMerge(accounts)
    merged.sort(key=lambda x: (x[0], x[1] if len(x) > 1 else ""))
    for acc in merged:
        print(' '.join(acc))

