#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<string>> accountsMerge(vector<vector<string>>& accounts) {
        unordered_map<string, string> email_to_name;
        unordered_map<string, string> parent;
        function<string(const string&)> find = [&](const string& x) {
            if (parent[x] == x) return x;
            return parent[x] = find(parent[x]);
        };
        auto unite = [&](const string& a, const string& b) {
            string ra = find(a);
            string rb = find(b);
            if (ra != rb) parent[rb] = ra;
        };
        for (auto& acc : accounts) {
            const string& name = acc[0];
            for (size_t i = 1; i < acc.size(); ++i) {
                const string& email = acc[i];
                email_to_name[email] = name;
                if (!parent.count(email)) parent[email] = email;
                unite(acc[1], email);
            }
        }
        unordered_map<string, vector<string>> groups;
        for (auto& p : parent) {
            string root = find(p.first);
            groups[root].push_back(p.first);
        }
        vector<vector<string>> res;
        for (auto& g : groups) {
            vector<string>& emails = g.second;
            sort(emails.begin(), emails.end());
            emails.erase(unique(emails.begin(), emails.end()), emails.end());
            vector<string> account;
            account.push_back(email_to_name[g.first]);
            account.insert(account.end(), emails.begin(), emails.end());
            res.push_back(move(account));
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<vector<string>> accounts;
    for (int i = 0; i < N; ++i) {
        string name;
        cin >> name;
        int M; cin >> M;
        vector<string> acc; acc.push_back(name);
        for (int j = 0; j < M; ++j) {
            string email; cin >> email;
            acc.push_back(email);
        }
        accounts.push_back(move(acc));
    }
    Solution sol;
    vector<vector<string>> merged = sol.accountsMerge(accounts);
    sort(merged.begin(), merged.end(), [](const vector<string>& a, const vector<string>& b) {
        if (a[0] != b[0]) return a[0] < b[0];
        string a_email = a.size() > 1 ? a[1] : "";
        string b_email = b.size() > 1 ? b[1] : "";
        return a_email < b_email;
    });
    for (auto& acc : merged) {
        for (size_t i = 0; i < acc.size(); ++i) {
            cout << acc[i] << (i + 1 == acc.size() ? '\n' : ' ');
        }
    }
    return 0;
}
